/**
 * JSON schemas, TypeScript types, and AJV validators for OwlDB API data.
 */

import type { JSONSchema } from "json-schema-to-ts";
import { FromSchema } from "json-schema-to-ts";
import { $Compiler, wrapCompilerAsTypeGuard } from "json-schema-to-ts";
import Ajv from "ajv";

/** Single AJV instance for all schema compilation. */
const ajv = new Ajv();
const $compile: $Compiler = (schema) => ajv.compile(schema);
const compile = wrapCompilerAsTypeGuard($compile);

// ---------------------------------------------------------------------------
// Auth
// ---------------------------------------------------------------------------

export const AuthResponseSchema = {
  $id: "auth-response.json",
  $schema: "http://json-schema.org/draft-07/schema",
  title: "AuthResponse",
  type: "object",
  required: ["token"],
  properties: {
    token: { type: "string" },
  },
  additionalProperties: true,
} as const satisfies JSONSchema;

export type AuthResponse = FromSchema<typeof AuthResponseSchema>;
export const isAuthResponse = compile(AuthResponseSchema);

// ---------------------------------------------------------------------------
// Post document
// ---------------------------------------------------------------------------

export const PostDocSchema = {
  $id: "post-doc.json",
  $schema: "http://json-schema.org/draft-07/schema",
  title: "PostDoc",
  type: "object",
  required: ["msg"],
  properties: {
    msg: { type: "string" },
    parent: { type: "string" },
    reactions: {
      type: "object",
      additionalProperties: {
        type: "array",
        items: { type: "string" },
      },
    },
    extensions: {
      type: "object",
      additionalProperties: true,
    },
  },
  additionalProperties: true,
} as const satisfies JSONSchema;

export type PostDoc = FromSchema<typeof PostDocSchema>;
export const isPostDoc = compile(PostDocSchema);

// ---------------------------------------------------------------------------
// Generic database document (returned in collection listings)
// ---------------------------------------------------------------------------

export const DbDocSchema = {
  $id: "db-doc.json",
  $schema: "http://json-schema.org/draft-07/schema",
  title: "DbDoc",
  type: "object",
  required: ["path", "doc"],
  properties: {
    path: { type: "string" },
    doc: { type: "object", additionalProperties: true },
    meta: {
      type: "object",
      properties: {
        createdAt: { type: "string" },
        createdBy: { type: "string" },
        lastModifiedAt: { type: "string" },
        lastModifiedBy: { type: "string" },
      },
      additionalProperties: true,
    },
  },
  additionalProperties: true,
} as const satisfies JSONSchema;

export type DbDoc = FromSchema<typeof DbDocSchema>;
export const isDbDoc = compile(DbDocSchema);

// ---------------------------------------------------------------------------
// Collection (array of documents)
// ---------------------------------------------------------------------------

export const CollectionSchema = {
  $id: "collection.json",
  $schema: "http://json-schema.org/draft-07/schema",
  title: "Collection",
  type: "array",
  items: {
    type: "object",
    required: ["path", "doc"],
    properties: {
      path: { type: "string" },
      doc: { type: "object", additionalProperties: true },
      meta: {
        type: "object",
        properties: {
          createdAt: { type: "string" },
          createdBy: { type: "string" },
        },
        additionalProperties: true,
      },
    },
    additionalProperties: true,
  },
} as const satisfies JSONSchema;

export type Collection = FromSchema<typeof CollectionSchema>;
export const isCollection = compile(CollectionSchema);

// ---------------------------------------------------------------------------
// Post create response
// ---------------------------------------------------------------------------

export const PostCreateResponseSchema = {
  $id: "post-create-response.json",
  $schema: "http://json-schema.org/draft-07/schema",
  title: "PostCreateResponse",
  type: "object",
  required: ["uri"],
  properties: {
    uri: { type: "string" },
  },
  additionalProperties: true,
} as const satisfies JSONSchema;

export type PostCreateResponse = FromSchema<typeof PostCreateResponseSchema>;
export const isPostCreateResponse = compile(PostCreateResponseSchema);

// ---------------------------------------------------------------------------
// Application domain types
// ---------------------------------------------------------------------------

export interface PostMeta {
  createdAt: string;
  createdBy: string;
}

export interface Post {
  path: string;
  doc: PostDoc;
  meta: PostMeta;
}

export interface Workspace {
  path: string;
  name: string;
}

export interface Channel {
  path: string;
  name: string;
}

/** Extract the last path segment as a name (URL-decoded). */
export function nameFromPath(path: string): string {
  const parts = path.split("/").filter(Boolean);
  const last = parts[parts.length - 1] ?? "";
  try {
    return decodeURIComponent(last);
  } catch {
    return last;
  }
}

/**
 * OwlDB API client — all HTTP/SSE calls to the database.
 */

import { fetchEventSource } from "@microsoft/fetch-event-source";
import { slog } from "./slog";
import {
  isAuthResponse,
  isCollection,
  isPostCreateResponse,
  Collection,
  PostDoc,
  nameFromPath,
  Workspace,
  Channel,
  Post,
  isPostDoc,
} from "./types";

declare const process: {
  env: { DATABASE_HOST: string; DATABASE_PATH: string; AUTH_PATH: string };
};

export const DB_HOST = process.env.DATABASE_HOST;
export const DB_PATH = process.env.DATABASE_PATH;
export const AUTH_PATH_ENV = process.env.AUTH_PATH;

/** Full base URL for the database (ends with /). */
export const DB_URL = `${DB_HOST}${DB_PATH}`;
/** Full URL for auth endpoint. */
export const AUTH_URL = `${DB_HOST}${AUTH_PATH_ENV}`;

// ---------------------------------------------------------------------------
// Auth
// ---------------------------------------------------------------------------

/** Login with username. Returns bearer token. */
export async function login(username: string): Promise<string> {
  const res = await fetch(AUTH_URL, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ username }),
  });
  if (!res.ok) {
    throw new Error(`Login failed: ${res.status} ${res.statusText}`);
  }
  const data: unknown = await res.json();
  if (!isAuthResponse(data)) throw new Error("Invalid auth response from server");
  return data.token;
}

/** Logout — destroys the bearer token on the server. */
export async function logout(token: string): Promise<void> {
  const res = await fetch(AUTH_URL, {
    method: "DELETE",
    headers: { Authorization: `Bearer ${token}` },
  });
  if (!res.ok && res.status !== 204) {
    slog.warn("Logout request failed", ["status", res.status]);
  }
}

// ---------------------------------------------------------------------------
// Workspaces
// ---------------------------------------------------------------------------

/** List all workspaces in the database. */
export async function listWorkspaces(token: string): Promise<Workspace[]> {
  const res = await fetch(DB_URL, {
    headers: { Authorization: `Bearer ${token}` },
  });
  if (!res.ok) throw new Error(`Failed to list workspaces: ${res.status}`);
  const data: unknown = await res.json();
  if (!isCollection(data)) {
    slog.warn("Unexpected workspace listing format, treating as empty");
    return [];
  }
  return data.map((d) => ({
    path: d.path,
    name: nameFromPath(d.path),
  }));
}

/** Create a new workspace. Throws on error (e.g., 409 conflict). */
export async function createWorkspace(token: string, name: string): Promise<void> {
  const res = await fetch(`${DB_URL}${encodeURIComponent(name)}`, {
    method: "PUT",
    headers: {
      Authorization: `Bearer ${token}`,
      "Content-Type": "application/json",
    },
    body: JSON.stringify({}),
  });
  if (!res.ok) {
    const msg = res.status === 409 ? "Workspace already exists" : `Error ${res.status}`;
    throw new Error(msg);
  }
  // Create the channels/ collection inside the workspace
  await fetch(`${DB_URL}${encodeURIComponent(name)}/channels/`, {
    method: "PUT",
    headers: {
      Authorization: `Bearer ${token}`,
      "Content-Type": "application/json",
    },
    body: JSON.stringify({}),
  });
}

/** Open (load) a workspace by fetching its channels. Throws if not found. */
export async function openWorkspace(token: string, name: string): Promise<Channel[]> {
  const res = await fetch(`${DB_URL}${encodeURIComponent(name)}/channels/`, {
    headers: { Authorization: `Bearer ${token}` },
  });
  if (res.status === 404) throw new Error(`Workspace "${name}" not found`);
  if (!res.ok) throw new Error(`Failed to open workspace: ${res.status}`);
  const data: unknown = await res.json();
  if (!isCollection(data)) {
    slog.warn("Unexpected channels format");
    return [];
  }
  return data.map((d) => ({
    path: d.path,
    name: nameFromPath(d.path),
  }));
}

/** Delete a workspace. Throws if not found. */
export async function deleteWorkspace(token: string, name: string): Promise<void> {
  const res = await fetch(`${DB_URL}${encodeURIComponent(name)}`, {
    method: "DELETE",
    headers: { Authorization: `Bearer ${token}` },
  });
  if (res.status === 404) throw new Error(`Workspace "${name}" not found`);
  if (!res.ok) throw new Error(`Failed to delete workspace: ${res.status}`);
}

// ---------------------------------------------------------------------------
// Channels
// ---------------------------------------------------------------------------

/** List channels in a workspace. */
export async function listChannels(token: string, workspace: string): Promise<Channel[]> {
  const res = await fetch(`${DB_URL}${encodeURIComponent(workspace)}/channels/`, {
    headers: { Authorization: `Bearer ${token}` },
  });
  if (!res.ok) throw new Error(`Failed to list channels: ${res.status}`);
  const data: unknown = await res.json();
  if (!isCollection(data)) return [];
  return data.map((d) => ({
    path: d.path,
    name: nameFromPath(d.path),
  }));
}

/** Create a new channel in a workspace. */
export async function createChannel(
  token: string,
  workspace: string,
  name: string,
): Promise<void> {
  const res = await fetch(
    `${DB_URL}${encodeURIComponent(workspace)}/channels/${encodeURIComponent(name)}`,
    {
      method: "PUT",
      headers: {
        Authorization: `Bearer ${token}`,
        "Content-Type": "application/json",
      },
      body: JSON.stringify({}),
    },
  );
  if (!res.ok) {
    const msg = res.status === 409 ? "Channel already exists" : `Error ${res.status}`;
    throw new Error(msg);
  }
  // Create posts/ collection
  await fetch(
    `${DB_URL}${encodeURIComponent(workspace)}/channels/${encodeURIComponent(name)}/posts/`,
    {
      method: "PUT",
      headers: {
        Authorization: `Bearer ${token}`,
        "Content-Type": "application/json",
      },
      body: JSON.stringify({}),
    },
  );
}

/** Open a channel — verifies it exists and returns a confirmation. */
export async function openChannel(
  token: string,
  workspace: string,
  name: string,
): Promise<void> {
  const res = await fetch(
    `${DB_URL}${encodeURIComponent(workspace)}/channels/${encodeURIComponent(name)}/posts/`,
    {
      headers: { Authorization: `Bearer ${token}` },
    },
  );
  if (res.status === 404) throw new Error(`Channel "${name}" not found`);
  if (!res.ok) throw new Error(`Failed to open channel: ${res.status}`);
}

/** Delete a channel from a workspace. */
export async function deleteChannel(
  token: string,
  workspace: string,
  name: string,
): Promise<void> {
  const res = await fetch(
    `${DB_URL}${encodeURIComponent(workspace)}/channels/${encodeURIComponent(name)}`,
    {
      method: "DELETE",
      headers: { Authorization: `Bearer ${token}` },
    },
  );
  if (res.status === 404) throw new Error(`Channel "${name}" not found`);
  if (!res.ok) throw new Error(`Failed to delete channel: ${res.status}`);
}

// ---------------------------------------------------------------------------
// Posts
// ---------------------------------------------------------------------------

/** Create a post in a channel. Returns the created document URI. */
export async function createPost(
  token: string,
  workspace: string,
  channel: string,
  msg: string,
  parent: string = "",
): Promise<string> {
  const res = await fetch(
    `${DB_URL}${encodeURIComponent(workspace)}/channels/${encodeURIComponent(channel)}/posts/`,
    {
      method: "POST",
      headers: {
        Authorization: `Bearer ${token}`,
        "Content-Type": "application/json",
      },
      body: JSON.stringify({ msg, parent }),
    },
  );
  if (!res.ok) throw new Error(`Failed to create post: ${res.status}`);
  const data: unknown = await res.json();
  if (!isPostCreateResponse(data)) throw new Error("Invalid post create response");
  return data.uri;
}

/** Update a post's reactions via PATCH. */
export async function patchReactions(
  token: string,
  postFullPath: string,
  reactions: Record<string, string[]>,
): Promise<void> {
  const url = `${DB_HOST}${postFullPath}`;
  const res = await fetch(url, {
    method: "PATCH",
    headers: {
      Authorization: `Bearer ${token}`,
      "Content-Type": "application/json",
    },
    body: JSON.stringify([
      { op: "ObjectAdd", path: "/reactions", value: reactions },
    ]),
  });
  if (!res.ok) throw new Error(`Failed to patch reactions: ${res.status}`);
}

// ---------------------------------------------------------------------------
// SSE subscription
// ---------------------------------------------------------------------------

export interface SSEPostEvent {
  eventType: "put" | "patch" | "delete";
  path: string;
  doc?: PostDoc;
  meta?: { createdAt: string; createdBy: string };
}

/**
 * Subscribe to live post updates via Server-Sent Events.
 * Calls onPost for each received post event.
 * Returns an AbortController you can use to unsubscribe.
 */
export function subscribeToChannel(
  token: string,
  workspace: string,
  channel: string,
  onPost: (event: SSEPostEvent) => void,
  onError?: (err: unknown) => void,
): AbortController {
  const controller = new AbortController();
  const url = `${DB_URL}${encodeURIComponent(workspace)}/channels/${encodeURIComponent(channel)}/posts/`;

  fetchEventSource(url, {
    headers: { Authorization: `Bearer ${token}` },
    signal: controller.signal,
    onmessage(ev) {
      try {
        const data: unknown = JSON.parse(ev.data);
        if (typeof data !== "object" || data === null) return;

        const d = data as Record<string, unknown>;
        const path = typeof d["path"] === "string" ? d["path"] : "";
        const rawDoc = d["doc"];
        const rawMeta = d["meta"];

        // Determine event type from SSE event type field or 'type' in data
        let eventType: "put" | "patch" | "delete" = "put";
        if (ev.event === "delete" || d["type"] === "delete") {
          eventType = "delete";
        } else if (ev.event === "patch" || d["type"] === "patch") {
          eventType = "patch";
        } else if (ev.event === "put" || d["type"] === "put") {
          eventType = "put";
        }

        const doc = isPostDoc(rawDoc) ? rawDoc : undefined;
        const meta =
          rawMeta &&
          typeof rawMeta === "object" &&
          "createdAt" in rawMeta &&
          "createdBy" in rawMeta
            ? {
                createdAt: String((rawMeta as Record<string, unknown>)["createdAt"]),
                createdBy: String((rawMeta as Record<string, unknown>)["createdBy"]),
              }
            : undefined;

        onPost({ eventType, path, doc, meta });
      } catch (e) {
        slog.warn("Failed to parse SSE event", ["error", e]);
      }
    },
    onerror(err) {
      slog.warn("SSE error", ["err", err]);
      if (onError) onError(err);
      throw err; // stop retrying on persistent error
    },
  }).catch((e) => {
    // Absorb AbortError from controller.abort()
    if (e instanceof DOMException && e.name === "AbortError") return;
    slog.warn("SSE connection error", ["error", e]);
  });

  return controller;
}

/**
 * Application state management using a simple pub/sub EventTarget store.
 */

import { Post, Workspace, Channel } from "./types";
import { SSEPostEvent, subscribeToChannel } from "./api";
import { slog } from "./slog";

// ---------------------------------------------------------------------------
// State shape
// ---------------------------------------------------------------------------

export interface AppState {
  /** Currently logged-in username, null if not logged in. */
  username: string | null;
  /** Bearer token for API calls. */
  token: string | null;
  /** All known workspaces. */
  workspaces: Workspace[];
  /** Name of the currently open workspace. */
  currentWorkspace: string | null;
  /** Channels in the currently open workspace. */
  channels: Channel[];
  /** Name of the currently open channel. */
  currentChannel: string | null;
  /** Posts in the currently open channel (live via SSE). */
  posts: Map<string, Post>;
  /** Global error message (null = no error). */
  error: string | null;
  /** Path of the post being replied to (null = top-level). */
  replyTo: string | null;
}

// ---------------------------------------------------------------------------
// Store
// ---------------------------------------------------------------------------

class AppStore extends EventTarget {
  private _state: AppState = {
    username: null,
    token: null,
    workspaces: [],
    currentWorkspace: null,
    channels: [],
    currentChannel: null,
    posts: new Map(),
    error: null,
    replyTo: null,
  };

  /** Current state snapshot. */
  get state(): Readonly<AppState> {
    return this._state;
  }

  /** Update state and notify listeners. */
  setState(update: Partial<AppState>): void {
    this._state = { ...this._state, ...update };
    this.dispatchEvent(new CustomEvent("state-change", { detail: this._state }));
  }

  /** Convenience: set error. */
  setError(msg: string | null): void {
    this.setState({ error: msg });
  }

  /** Clear error. */
  clearError(): void {
    this.setState({ error: null });
  }
}

export const store = new AppStore();

// ---------------------------------------------------------------------------
// SSE subscription management
// ---------------------------------------------------------------------------

let sseController: AbortController | null = null;

/** Start SSE subscription for the given channel. Cancels any prior subscription. */
export function startChannelSubscription(workspace: string, channel: string): void {
  stopChannelSubscription();

  const { token } = store.state;
  if (!token) return;

  sseController = subscribeToChannel(
    token,
    workspace,
    channel,
    (event: SSEPostEvent) => handleSSEEvent(event),
    (err) => slog.warn("SSE error in channel subscription", ["err", err]),
  );
}

/** Stop the current SSE subscription. */
export function stopChannelSubscription(): void {
  if (sseController) {
    sseController.abort();
    sseController = null;
  }
}

function handleSSEEvent(event: SSEPostEvent): void {
  const { posts } = store.state;
  const newPosts = new Map(posts);

  if (event.eventType === "delete") {
    newPosts.delete(event.path);
  } else if (event.doc && event.meta) {
    // put or patch — upsert the post
    newPosts.set(event.path, {
      path: event.path,
      doc: event.doc,
      meta: event.meta,
    });
  } else if (event.eventType === "put" && event.doc) {
    // put without meta — create with empty meta
    newPosts.set(event.path, {
      path: event.path,
      doc: event.doc,
      meta: { createdAt: "", createdBy: "" },
    });
  } else if (event.eventType === "patch" && event.doc) {
    // patch — merge into existing
    const existing = newPosts.get(event.path);
    if (existing) {
      newPosts.set(event.path, {
        ...existing,
        doc: { ...existing.doc, ...event.doc },
      });
    } else {
      newPosts.set(event.path, {
        path: event.path,
        doc: event.doc,
        meta: { createdAt: "", createdBy: "" },
      });
    }
  }

  store.setState({ posts: newPosts });
}

/** Reset posts and close the current channel. */
export function closeChannel(): void {
  stopChannelSubscription();
  store.setState({ currentChannel: null, posts: new Map(), replyTo: null });
}

/** Reset everything related to workspace/channel when workspace closes. */
export function closeWorkspace(): void {
  closeChannel();
  store.setState({ currentWorkspace: null, channels: [] });
}

/** Reset all state on logout. */
export function resetState(): void {
  stopChannelSubscription();
  store.setState({
    username: null,
    token: null,
    workspaces: [],
    currentWorkspace: null,
    channels: [],
    currentChannel: null,
    posts: new Map(),
    error: null,
    replyTo: null,
  });
}

/**
 * Minimal markdown formatter for posts.
 * Converts: **bold**, *italic*, [text](url), :reaction:, and \n to <br>.
 */

/** Map of supported reaction names to iconify icon names. */
const REACTION_ICONS: Record<string, string> = {
  ":smile:": "mdi:emoticon-happy-outline",
  ":frown:": "mdi:emoticon-sad-outline",
  ":like:": "mdi:thumb-up-outline",
  ":celebrate:": "mdi:party-popper",
};

/**
 * Render a plain-text post message as safe HTML with markdown formatting.
 * Returns an HTML string — caller must set innerHTML.
 */
export function renderMarkdown(text: string): string {
  // Escape HTML special chars first (prevent XSS)
  let html = escapeHtml(text);

  // Replace **bold** with <strong>
  html = html.replace(/\*\*([^*]+)\*\*/g, "<strong>$1</strong>");

  // Replace *italic* with <em>
  html = html.replace(/\*([^*]+)\*/g, "<em>$1</em>");

  // Replace [text](url) with <a href="url">text</a>
  // Only allow http/https URLs
  html = html.replace(
    /\[([^\]]+)\]\((https?:\/\/[^)]+)\)/g,
    '<a href="$2" target="_blank" rel="noopener noreferrer">$1</a>',
  );

  // Replace :reaction: with iconify icons (for known reactions)
  html = html.replace(/:([a-z][a-z-]*):/g, (match) => {
    const icon = REACTION_ICONS[match];
    if (icon) {
      return `<iconify-icon icon="${icon}" aria-label="${match}" class="inline-icon"></iconify-icon>`;
    }
    return match; // unknown reaction — leave as-is
  });

  // Convert \n to <br>
  html = html.replace(/\n/g, "<br>");

  return html;
}

/** HTML-escape a string to prevent XSS. */
function escapeHtml(text: string): string {
  return text
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#39;");
}

/** Format an ISO timestamp for display. */
export function formatTime(iso: string): string {
  if (!iso) return "";
  try {
    const d = new Date(iso);
    return d.toLocaleString();
  } catch {
    return iso;
  }
}

