        }

        .modal {
          background: #1e1e2e;
          color: #cdd6f4;
          border-radius: 12px;
          padding: 2rem;
          width: 340px;
          box-shadow: 0 8px 32px rgba(0, 0, 0, 0.6);
          display: flex;
          flex-direction: column;
