          padding: 0.6rem 1rem;
          border: none;
          border-radius: 6px;
          background: #89b4fa;
          color: #1e1e2e;
          font-size: 1rem;
          font-weight: 600;
          cursor: pointer;
        }

        button:hover { background: #74c7ec; }

        .error {
          color: #f38ba8;
          font-size: 0.85rem;
          text-align: center;
          min-height: 1.2em;
        }

        .hidden { display: none !important; }
      </style>

      <div class="backdrop" id="backdrop">
        <div class="modal" role="dialog" aria-modal="true" aria-labelledby="login-title">
          <h2 id="login-title">Welcome to M3ssag1n8</h2>
          <input
            type="text"
            id="username-input"
            placeholder="Username"
            aria-label="Username"
            autocomplete="username"
          />
          <button id="login-btn">Login</button>
          <p class="error" id="login-error" role="alert"></p>
        </div>
      </div>
    `;
  }

  private bindEvents(): void {
    const input = this.shadow.getElementById("username-input") as HTMLInputElement;
    const btn = this.shadow.getElementById("login-btn") as HTMLButtonElement;
    const errorEl = this.shadow.getElementById("login-error") as HTMLParagraphElement;

    const doLogin = async (): Promise<void> => {
      const username = input.value.trim();
      if (!username) {
        errorEl.textContent = "Please enter a username.";
        return;
      }
      errorEl.textContent = "";
      btn.disabled = true;
      try {
        const token = await login(username);
        store.setState({ username, token });
        this.hide();
        // Dispatch login event so the app can refresh workspaces
        this.dispatchEvent(new CustomEvent("user-logged-in", { bubbles: true }));
      } catch (e) {
        errorEl.textContent = e instanceof Error ? e.message : "Login failed";
      } finally {
        btn.disabled = false;
      }
    };

    btn.addEventListener("click", doLogin);
    input.addEventListener("keydown", (e: KeyboardEvent) => {
      if (e.key === "Enter") doLogin();
    });
  }

  show(): void {
    const backdrop = this.shadow.getElementById("backdrop");
    if (backdrop) backdrop.classList.remove("hidden");
    // Reset input
    const input = this.shadow.getElementById("username-input") as HTMLInputElement;
    if (input) {
      input.value = "";
      input.focus();
    }
    const err = this.shadow.getElementById("login-error");
    if (err) err.textContent = "";
  }

  hide(): void {
    const backdrop = this.shadow.getElementById("backdrop");
    if (backdrop) backdrop.classList.add("hidden");
  }
}

