          font-size: 0.75rem;
          cursor: pointer;
          flex: 1;
          font-weight: 600;
        }

        #open-workspace-btn { background: #89b4fa; color: #1e1e2e; }
        #create-workspace-btn { background: #a6e3a1; color: #1e1e2e; }
        #delete-workspace-btn { background: #f38ba8; color: #1e1e2e; }
        #refresh-workspaces-btn {
          background: #45475a;
          color: #cdd6f4;
          flex: 0 0 auto;
          font-size: 0.7rem;
        }

