        </div>
        <button id="refresh-workspaces-btn" title="Refresh workspace list">
          <iconify-icon icon="mdi:refresh" aria-label="refresh"></iconify-icon> Refresh
        </button>
      </div>

      <div class="error hidden" id="ws-error" role="alert">
        <span id="ws-error-msg"></span>
        <button id="ws-dismiss-error" aria-label="Dismiss error">×</button>
      </div>

      <ul class="workspace-list" id="workspace-list" aria-label="Workspace list"></ul>
    `;
  }

  private bindEvents(): void {
    const nameInput = this.shadow.getElementById("workspace-name-input") as HTMLInputElement;
    const openBtn = this.shadow.getElementById("open-workspace-btn") as HTMLButtonElement;
    const createBtn = this.shadow.getElementById("create-workspace-btn") as HTMLButtonElement;
    const deleteBtn = this.shadow.getElementById("delete-workspace-btn") as HTMLButtonElement;
    const refreshBtn = this.shadow.getElementById("refresh-workspaces-btn") as HTMLButtonElement;
    const dismissBtn = this.shadow.getElementById("ws-dismiss-error") as HTMLButtonElement;

    openBtn.addEventListener("click", () => this.handleOpen(nameInput.value.trim()));
    createBtn.addEventListener("click", () => this.handleCreate(nameInput.value.trim()));
    deleteBtn.addEventListener("click", () => this.handleDelete(nameInput.value.trim()));
    refreshBtn.addEventListener("click", () => this.handleRefresh());
    dismissBtn.addEventListener("click", () => this.clearError());

    nameInput.addEventListener("keydown", (e: KeyboardEvent) => {
      if (e.key === "Enter") this.handleOpen(nameInput.value.trim());
    });
  }

  private showError(msg: string): void {
    const errDiv = this.shadow.getElementById("ws-error")!;
    const errMsg = this.shadow.getElementById("ws-error-msg")!;
    errDiv.classList.remove("hidden");
    errMsg.textContent = msg;
  }

  private clearError(): void {
    this.shadow.getElementById("ws-error")!.classList.add("hidden");
  }

  private async handleOpen(name: string): Promise<void> {
    if (!name) return;
    this.clearError();
    const { token } = store.state;
    if (!token) return;
    try {
      const channels: Channel[] = await apiOpenWorkspace(token, name);
      closeWorkspace();
      store.setState({ currentWorkspace: name, channels });
    } catch (e) {
      this.showError(e instanceof Error ? e.message : "Error opening workspace");
    }
  }

  private async handleCreate(name: string): Promise<void> {
    if (!name) return;
    this.clearError();
    const { token } = store.state;
    if (!token) return;
    try {
      await apiCreateWorkspace(token, name);
      // Auto-open after creation
      const channels: Channel[] = await apiOpenWorkspace(token, name);
      closeWorkspace();
      store.setState({ currentWorkspace: name, channels });
      // Refresh list
      await this.loadWorkspaces();
    } catch (e) {
      this.showError(e instanceof Error ? e.message : "Error creating workspace");
    }
  }

  private async handleDelete(name: string): Promise<void> {
    if (!name) return;
    this.clearError();
    const { token, currentWorkspace } = store.state;
    if (!token) return;
    try {
      await apiDeleteWorkspace(token, name);
      // Always close current workspace after any delete
      closeWorkspace();
      await this.loadWorkspaces();
    } catch (e) {
      this.showError(e instanceof Error ? e.message : "Error deleting workspace");
    }
  }

  private async handleRefresh(): Promise<void> {
    this.clearError();
    await this.loadWorkspaces();
  }

  async loadWorkspaces(): Promise<void> {
    const { token } = store.state;
    if (!token) return;
    try {
      const workspaces = await listWorkspaces(token);
      store.setState({ workspaces });
    } catch (e) {
      this.showError(e instanceof Error ? e.message : "Error loading workspaces");
    }
  }

  private updateList(): void {
    const list = this.shadow.getElementById("workspace-list")!;
    const { workspaces, currentWorkspace } = store.state;
    list.innerHTML = "";
    for (const ws of workspaces) {
      const li = document.createElement("li");
      li.className = "workspace-item" + (ws.name === currentWorkspace ? " active" : "");
      li.textContent = ws.name;
      li.setAttribute("title", ws.name);
      li.addEventListener("click", () => {
        const input = this.shadow.getElementById("workspace-name-input") as HTMLInputElement;
        input.value = ws.name;
        this.handleOpen(ws.name);
      });
      list.appendChild(li);
    }
  }
}

