    `;
  }

  private bindEvents(): void {
    const nameInput = this.shadow.getElementById("channel-name-input") as HTMLInputElement;
    const openBtn = this.shadow.getElementById("open-channel-btn") as HTMLButtonElement;
    const createBtn = this.shadow.getElementById("create-channel-btn") as HTMLButtonElement;
    const deleteBtn = this.shadow.getElementById("delete-channel-btn") as HTMLButtonElement;
    const refreshBtn = this.shadow.getElementById("refresh-channels-btn") as HTMLButtonElement;
    const dismissBtn = this.shadow.getElementById("ch-dismiss-error") as HTMLButtonElement;

    openBtn.addEventListener("click", () => this.handleOpen(nameInput.value.trim()));
    createBtn.addEventListener("click", () => this.handleCreate(nameInput.value.trim()));
    deleteBtn.addEventListener("click", () => this.handleDelete(nameInput.value.trim()));
    refreshBtn.addEventListener("click", () => this.handleRefresh());
    dismissBtn.addEventListener("click", () => this.clearError());

    nameInput.addEventListener("keydown", (e: KeyboardEvent) => {
      if (e.key === "Enter") this.handleOpen(nameInput.value.trim());
    });
  }

  private showError(msg: string): void {
    const errDiv = this.shadow.getElementById("ch-error")!;
    const errMsg = this.shadow.getElementById("ch-error-msg")!;
    errDiv.classList.remove("hidden");
    errMsg.textContent = msg;
  }

  private clearError(): void {
    this.shadow.getElementById("ch-error")!.classList.add("hidden");
  }

  private async handleOpen(name: string): Promise<void> {
    if (!name) return;
    this.clearError();
    const { token, currentWorkspace } = store.state;
    if (!token || !currentWorkspace) return;
    try {
      await apiOpenChannel(token, currentWorkspace, name);
      closeChannel();
      store.setState({ currentChannel: name });
      startChannelSubscription(currentWorkspace, name);
    } catch (e) {
      this.showError(e instanceof Error ? e.message : "Error opening channel");
    }
  }

  private async handleCreate(name: string): Promise<void> {
    if (!name) return;
    this.clearError();
    const { token, currentWorkspace } = store.state;
    if (!token || !currentWorkspace) return;
    try {
      await apiCreateChannel(token, currentWorkspace, name);
      // Auto-open after creation
      closeChannel();
      store.setState({ currentChannel: name });
      startChannelSubscription(currentWorkspace, name);
      // Refresh channels list
      await this.loadChannels();
    } catch (e) {
      this.showError(e instanceof Error ? e.message : "Error creating channel");
    }
  }

  private async handleDelete(name: string): Promise<void> {
    if (!name) return;
    this.clearError();
    const { token, currentWorkspace } = store.state;
    if (!token || !currentWorkspace) return;
    try {
      await apiDeleteChannel(token, currentWorkspace, name);
      closeChannel();
      await this.loadChannels();
    } catch (e) {
      this.showError(e instanceof Error ? e.message : "Error deleting channel");
    }
  }

  private async handleRefresh(): Promise<void> {
    this.clearError();
    await this.loadChannels();
  }

  async loadChannels(): Promise<void> {
    const { token, currentWorkspace } = store.state;
    if (!token || !currentWorkspace) return;
    try {
      const channels = await listChannels(token, currentWorkspace);
      store.setState({ channels });
    } catch (e) {
      this.showError(e instanceof Error ? e.message : "Error loading channels");
    }
  }

  private onStateChange(): void {
    const { currentWorkspace, channels, currentChannel } = store.state;

    // Show/hide based on workspace
    if (!currentWorkspace) {
      this.setAttribute("hidden", "");
    } else {
      this.removeAttribute("hidden");
    }

    // Update workspace label
    const label = this.shadow.getElementById("workspace-name-label")!;
    label.textContent = currentWorkspace ?? "";

    // Update channel list
    const list = this.shadow.getElementById("channel-list")!;
    list.innerHTML = "";
    for (const ch of channels) {
      const li = document.createElement("li");
      li.className = "channel-item" + (ch.name === currentChannel ? " active" : "");
      li.textContent = ch.name;
      li.setAttribute("title", ch.name);
      li.addEventListener("click", () => {
        const input = this.shadow.getElementById("channel-name-input") as HTMLInputElement;
        input.value = ch.name;
        this.handleOpen(ch.name);
      });
      list.appendChild(li);
    }
  }
}

