  private bindEvents(): void {
    const input = this.shadow.getElementById("post-input") as HTMLTextAreaElement;
    const submitBtn = this.shadow.getElementById("post-submit-btn") as HTMLButtonElement;
    const closeReplyBtn = this.shadow.getElementById("close-reply-btn") as HTMLButtonElement;
    const fmtBold = this.shadow.getElementById("fmt-bold") as HTMLButtonElement;
    const fmtItalic = this.shadow.getElementById("fmt-italic") as HTMLButtonElement;
    const fmtLink = this.shadow.getElementById("fmt-link") as HTMLButtonElement;

    submitBtn.addEventListener("click", () => this.handleSubmit());

    input.addEventListener("keydown", (e: KeyboardEvent) => {
      if (e.key === "Enter" && !e.shiftKey) {
        e.preventDefault();
        this.handleSubmit();
      }
      // Shift+Enter inserts newline (default textarea behavior — just don't submit)
    });

    closeReplyBtn.addEventListener("click", () => this.cancelReply());

    fmtBold.addEventListener("click", () => this.insertFormat(input, "**", "**", "bold text"));
    fmtItalic.addEventListener("click", () => this.insertFormat(input, "*", "*", "italic text"));
    fmtLink.addEventListener("click", () =>
      this.insertFormat(input, "[", "](https://example.com)", "link text"),
    );

    // Reaction insert buttons
    this.shadow.querySelectorAll(".reaction-insert").forEach((btn) => {
      btn.addEventListener("click", () => {
        const reaction = (btn as HTMLElement).dataset["reaction"] ?? "";
        this.insertAtCursor(input, reaction);
      });
    });
  }

  private insertFormat(
    textarea: HTMLTextAreaElement,
    before: string,
    after: string,
    placeholder: string,
  ): void {
    const start = textarea.selectionStart;
    const end = textarea.selectionEnd;
    const selected = textarea.value.substring(start, end) || placeholder;
    const replacement = `${before}${selected}${after}`;
    textarea.setRangeText(replacement, start, end, "end");
    textarea.focus();
  }

  private insertAtCursor(textarea: HTMLTextAreaElement, text: string): void {
    const start = textarea.selectionStart;
    const end = textarea.selectionEnd;
    textarea.setRangeText(text, start, end, "end");
    textarea.focus();
  }

  private async handleSubmit(): Promise<void> {
    const input = this.shadow.getElementById("post-input") as HTMLTextAreaElement;
    const msg = input.value;
    if (!msg.trim()) return;

    const { token, currentWorkspace, currentChannel } = store.state;
    if (!token || !currentWorkspace || !currentChannel) return;

    try {
      await apiCreatePost(
        token,
        currentWorkspace,
        currentChannel,
        msg,
        this.replyTo ?? "",
      );
      input.value = "";
      this.cancelReply();
    } catch (e) {
      console.error("Failed to post:", e);
    }
  }

  /** Called when a reply button inside a post is clicked. */
  private startReply(postPath: string, postContent: string): void {
    this.replyTo = postPath;
    const ctx = this.shadow.getElementById("reply-context")!;
    const ctxText = this.shadow.getElementById("reply-context-text")!;
    ctx.classList.remove("hidden");
    const preview = postContent.length > 40 ? postContent.substring(0, 40) + "…" : postContent;
    ctxText.textContent = `Replying to: "${preview}"`;

    // Move input area to after the post being replied to
    const postEl = this.shadow.querySelector(`[data-path="${CSS.escape(postPath)}"]`);
    const inputArea = this.shadow.getElementById("input-area")!;
    if (postEl) {
      postEl.after(inputArea);
    }

    const inputEl = this.shadow.getElementById("post-input") as HTMLTextAreaElement;
    inputEl.focus();
  }

  private cancelReply(): void {
    this.replyTo = null;
    const ctx = this.shadow.getElementById("reply-context")!;
    ctx.classList.add("hidden");

    // Move input area back to the bottom
    const panel = this.shadow.host as HTMLElement;
    const inputArea = this.shadow.getElementById("input-area")!;
    this.shadow.appendChild(inputArea);
  }

  private async handleReaction(
    postPath: string,
    reactionKey: string,
    currentReactions: Record<string, string[]>,
  ): Promise<void> {
    const { token, username } = store.state;
    if (!token || !username) return;

    const newReactions = { ...currentReactions };
    const users = newReactions[reactionKey] ? [...newReactions[reactionKey]] : [];
    const idx = users.indexOf(username);
    if (idx >= 0) {
      users.splice(idx, 1);
    } else {
      users.push(username);
    }
    newReactions[reactionKey] = users;

    try {
      // postPath is the full db path like /v1/m3ssag1n8/ws/channels/ch/posts/id
      await patchReactions(token, postPath, newReactions);
    } catch (e) {
      console.error("Failed to update reaction:", e);
    }
  }

  private onStateChange(): void {
    const { currentChannel, currentWorkspace } = store.state;

    if (!currentWorkspace || !currentChannel) {
      this.setAttribute("hidden", "");
      return;
    }
    this.removeAttribute("hidden");

    // Update channel label
    const label = this.shadow.getElementById("channel-name-label")!;
    label.textContent = currentChannel;

    // Re-render posts
    this.renderPosts();
  }

  private renderPosts(): void {
    const { posts, username } = store.state;
    const postList = this.shadow.getElementById("post-list")!;

    // Ensure input-area is at the bottom of shadow root after render
    const inputArea = this.shadow.getElementById("input-area")!;

    // Build sorted array of all posts
    const allPosts = Array.from(posts.values());
    allPosts.sort((a, b) => {
      const ta = a.meta.createdAt || "";
      const tb = b.meta.createdAt || "";
      return ta < tb ? -1 : ta > tb ? 1 : 0;
    });

    // Separate top-level and replies
    const topLevel: Post[] = [];
    const byParent = new Map<string, Post[]>();

    for (const post of allPosts) {
      const parent = post.doc.parent ?? "";
      if (!parent) {
        topLevel.push(post);
      } else {
        if (!byParent.has(parent)) byParent.set(parent, []);
        byParent.get(parent)!.push(post);
      }
    }

    // Clear and rebuild
    postList.innerHTML = "";

    if (topLevel.length === 0) {
      postList.innerHTML =
        '<p class="empty-state">No messages yet. Be the first to post!</p>';
      return;
    }

    // Recursively render posts
    const renderPost = (post: Post, depth: number): HTMLElement => {
      const div = document.createElement("div");
      div.className = "post-item";
      div.dataset["path"] = post.path;

      const reactions = (post.doc.reactions ?? {}) as Record<string, string[]>;
      const reactionHtml = REACTIONS.map((r) => {
        const users = reactions[r.key] ?? [];
        const count = users.length;
        const reacted = username ? users.includes(username) : false;
        return `<button
            class="reaction-btn${reacted ? " reacted" : ""}"
            data-reaction="${r.key}"
            data-path="${escapeAttr(post.path)}"
            aria-label="${r.label} (${count})"
            title="${r.key}"
          >
            <iconify-icon icon="${r.icon}" aria-label="${r.label}" class="inline-icon"></iconify-icon>
            <span class="reaction-count">${count}</span>
          </button>`;
      }).join("");

      div.innerHTML = `
        <div class="post-header">
          <span class="post-author">${escapeHtml(post.meta.createdBy || "unknown")}</span>
          <span class="post-time">${formatTime(post.meta.createdAt)}</span>
        </div>
        <div class="post-content">${renderMarkdown(post.doc.msg)}</div>
        <div class="post-actions">
          <button class="reply-btn" data-action="reply" data-path="${escapeAttr(post.path)}" aria-label="Reply to post">
            <iconify-icon icon="mdi:reply" aria-label="reply"></iconify-icon> Reply
          </button>
          ${reactionHtml}
        </div>
        <div class="replies"></div>
      `;

      // Bind reply button
      const replyBtn = div.querySelector('[data-action="reply"]') as HTMLButtonElement;
      replyBtn.addEventListener("click", (e) => {
        e.stopPropagation();
        this.startReply(post.path, post.doc.msg);
      });

      // Bind reaction buttons
      div.querySelectorAll(".reaction-btn").forEach((btn) => {
        btn.addEventListener("click", (e) => {
          e.stopPropagation();
          const key = (btn as HTMLElement).dataset["reaction"] ?? "";
          this.handleReaction(post.path, key, reactions);
        });
      });

      // Render nested replies
      const replies = byParent.get(post.path) ?? [];
      if (replies.length > 0) {
        const repliesDiv = div.querySelector(".replies")!;
        for (const reply of replies) {
          repliesDiv.appendChild(renderPost(reply, depth + 1));
        }
      }

      return div;
    };

    for (const post of topLevel) {
      postList.appendChild(renderPost(post, 0));
    }

    // If not in a reply context, ensure input is at the bottom of shadow root
    if (!this.replyTo) {
      this.shadow.appendChild(inputArea);
    }
  }
}

function escapeHtml(text: string): string {
  return text
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#39;");
}

function escapeAttr(text: string): string {
  return text.replace(/"/g, "&quot;");
}

