import { slog } from "./slog";
import { store, resetState } from "./state";
import { logout } from "./api";
import { LoginModal } from "./components/login-modal";
import { WorkspacePanel } from "./components/workspace-panel";
import { ChannelPanel } from "./components/channel-panel";
import { PostPanel } from "./components/post-panel";

/**
 * Declare names and types of environment variables.
 */
declare const process: {
  env: {
    DATABASE_HOST: string;
    DATABASE_PATH: string;
    AUTH_PATH: string;
  };
};

/**
 * Initial entry point of the application.
 */
function main(): void {
  slog.info("Using database", [
    "database",
    `${process.env.DATABASE_HOST}${process.env.DATABASE_PATH}`,
  ]);

  // Elements in the main document (not shadow DOM)
  const loginModal = document.getElementById("login-modal") as LoginModal | null;
  const usernameEl = document.getElementById("current-username");
  const logoutBtn = document.getElementById("logout-btn") as HTMLButtonElement | null;
  const workspacePanel = document.getElementById("workspace-panel") as WorkspacePanel | null;

  // Handle logout
  logoutBtn?.addEventListener("click", async () => {
    const { token } = store.state;
    if (token) {
      try {
        await logout(token);
      } catch (e) {
        slog.warn("Logout error", ["error", e]);
      }
    }
    resetState();
    // Update UI
    if (usernameEl) usernameEl.textContent = "";
    loginModal?.show();
  });

  // Listen for login event from modal
  document.addEventListener("user-logged-in", async () => {
    const { username } = store.state;
    if (usernameEl && username) {
      usernameEl.textContent = username;
    }
    // Load workspace list after login
    if (workspacePanel) {
      await workspacePanel.loadWorkspaces();
    }
  });

  // Sync username display with state
  store.addEventListener("state-change", () => {
    const { username } = store.state;
    if (usernameEl) {
      usernameEl.textContent = username ?? "";
    }
  });
}

/* Register event handler to run after the page is fully loaded. */
document.addEventListener("DOMContentLoaded", () => {
  main();
});

/// <reference types="cypress" />

declare namespace Cypress {
  interface Chainable {
    login(username: string): Chainable<void>;
    logout(): Chainable<void>;
    openWorkspace(workspace: string): Chainable<void>;
    createWorkspace(workspace: string): Chainable<void>;
    deleteWorkspace(workspace: string): Chainable<void>;
    openChannel(channel: string): Chainable<void>;
    createChannel(channel: string): Chainable<void>;
    deleteChannel(channel: string): Chainable<void>;
    createPost(post: string): Chainable<void>;
    getPost(post: string): Chainable<JQuery<Element>>;
    replyToPost(reply: string): Chainable<void>;
    reactToPost(reaction: string): Chainable<void>;
  }
}

/*
 * Custom commands for M3ssag1n8 application testing.
 *
 * All commands use IDs/selectors that match elements in the component
 * shadow DOMs. The cypress config has includeShadowDom: true so Cypress
 * automatically pierces shadow roots.
 */

/**
 * Login using given username.
 * Assumes that no one is currently logged in.
 */
Cypress.Commands.add("login", (username: string) => {
  cy.get("#username-input").type(username);
  cy.get("#login-btn").click();
});

/**
 * Logout the currently logged in user.
 * Assumes that a user is currently logged in.
 */
Cypress.Commands.add("logout", () => {
  cy.get("#logout-btn").click();
});

/**
 * Open a workspace.
 * Assumes that someone is logged in and that the workspace exists.
 */
Cypress.Commands.add("openWorkspace", (workspace: string) => {
  cy.get("#workspace-name-input").clear().type(workspace);
  cy.get("#open-workspace-btn").click();
});

/**
 * Create a workspace.
 * Assumes that someone is logged in and that the workspace does not exist.
 */
Cypress.Commands.add("createWorkspace", (workspace: string) => {
  cy.get("#workspace-name-input").clear().type(workspace);
  cy.get("#create-workspace-btn").click();
});

/**
 * Delete a workspace.
 * Assumes that someone is logged in and that the workspace exists.
 */
Cypress.Commands.add("deleteWorkspace", (workspace: string) => {
  cy.get("#workspace-name-input").clear().type(workspace);
  cy.get("#delete-workspace-btn").click();
});

/**
 * Open a channel.
 * Assumes that someone is logged in, a workspace is open, and that the channel
 * exists in that workspace.
 */
Cypress.Commands.add("openChannel", (channel: string) => {
  cy.get("#channel-name-input").clear().type(channel);
  cy.get("#open-channel-btn").click();
});

/**
 * Create a channel.
 * Assumes that someone is logged in, a workspace is open, and that the channel
 * does not exist in that workspace.
 */
Cypress.Commands.add("createChannel", (channel: string) => {
  cy.get("#channel-name-input").clear().type(channel);
  cy.get("#create-channel-btn").click();
});

/**
 * Delete a channel.
 * Assumes that someone is logged in, a workspace is open, and that the channel
 * exists in that workspace.
 */
Cypress.Commands.add("deleteChannel", (channel: string) => {
  cy.get("#channel-name-input").clear().type(channel);
  cy.get("#delete-channel-btn").click();
});

/**
 * Create a post.
 * Assumes that someone is logged in, a workspace is open, and a channel is open.
 */
Cypress.Commands.add("createPost", (post: string) => {
  cy.get("#post-input").type(post);
  cy.get("#post-submit-btn").click();
});

/**
 * Get a post by search text.
 * Assumes that someone is logged in, a workspace is open, and a channel is open.
 * Returns the enclosing post element.
 */
Cypress.Commands.add(
  "getPost",
  (searchText: string): Cypress.Chainable<JQuery<Element>> => {
    return cy.contains(".post-item", searchText);
  },
);

/**
 * Reply to a post.
 * Assumes subject is from getPost.
 */
Cypress.Commands.add(
  "replyToPost",
  { prevSubject: true },
  (subject, reply: string) => {
    cy.wrap(subject).find('[data-action="reply"]').first().click();
    cy.get("#post-input").clear().type(reply);
    cy.get("#post-submit-btn").click();
  },
);

/**
 * React to a post.
 * Assumes subject is from getPost.
 */
Cypress.Commands.add(
  "reactToPost",
  { prevSubject: true },
  (subject, reaction: string) => {
    cy.wrap(subject).find(`[data-reaction="${reaction}"]`).first().click();
  },
);

