import { slog } from "./slog";
import { store, resetState } from "./state";
import { login, logout } from "./api";
import "./components/workspace-panel";
import "./components/channel-panel";
import "./components/post-panel";

/**
 * Declare names and types of environment variables.
 */
declare const process: {
  env: {
    DATABASE_HOST: string;
    DATABASE_PATH: string;
    AUTH_PATH: string;
  };
};

/**
 * Initial entry point of the application.
 */
async function main(): Promise<void> {
  slog.info("Using database", [
    "database",
    `${process.env.DATABASE_HOST}${process.env.DATABASE_PATH}`,
  ]);

  // Light-DOM elements
  const loginBackdrop = document.getElementById("login-backdrop")!;
  const usernameInput = document.getElementById("username-input") as HTMLInputElement;
  const loginBtn = document.getElementById("login-btn") as HTMLButtonElement;
  const loginError = document.getElementById("login-error")!;
  const appEl = document.getElementById("app")!;
  const currentUsernameEl = document.getElementById("current-username")!;
  const logoutBtn = document.getElementById("logout-btn") as HTMLButtonElement;
  const workspacePanel = document.getElementById("workspace-panel") as any;

  // Show login modal
  function showLogin(): void {
    loginBackdrop.classList.remove("hidden");
    appEl.classList.remove("active");
    appEl.classList.add("app-blurred");
    usernameInput.value = "";
    loginError.textContent = "";
    usernameInput.focus();
  }

  // Hide login modal
  function hideLogin(): void {
    loginBackdrop.classList.add("hidden");
    appEl.classList.remove("app-blurred");
    appEl.classList.add("active");
  }

  // Handle login
  async function handleLogin(): Promise<void> {
    const username = usernameInput.value.trim();
    if (!username) {
      loginError.textContent = "Please enter a username.";
      return;
    }
    loginError.textContent = "";
    loginBtn.disabled = true;
    try {
      const token = await login(username);
      store.setState({ username, token });
      currentUsernameEl.textContent = username;
      hideLogin();
      // Load workspace list
      if (workspacePanel && typeof workspacePanel.loadWorkspaces === "function") {
        await workspacePanel.loadWorkspaces();
      }
    } catch (e) {
      loginError.textContent = e instanceof Error ? e.message : "Login failed";
    } finally {
      loginBtn.disabled = false;
    }
  }

  loginBtn.addEventListener("click", handleLogin);
  usernameInput.addEventListener("keydown", (e: KeyboardEvent) => {
    if (e.key === "Enter") handleLogin();
  });

  // Handle logout
  logoutBtn.addEventListener("click", async () => {
    const { token } = store.state;
    if (token) {
      try {
        await logout(token);
      } catch (e) {
        slog.warn("Logout error", ["error", e]);
      }
    }
    resetState();
    currentUsernameEl.textContent = "";
    showLogin();
  });

  // Show login on startup
  showLogin();
}

/* Register event handler to run after the page is fully loaded. */
document.addEventListener("DOMContentLoaded", () => {
  main();
});

