  createWorkspace as apiCreateWorkspace,
  openWorkspace as apiOpenWorkspace,
  deleteWorkspace as apiDeleteWorkspace,
  listChannels,
  createChannel as apiCreateChannel,
  openChannel as apiOpenChannel,
  deleteChannel as apiDeleteChannel,
  createPost as apiCreatePost,
  patchReactions,
  DB_PATH,
} from "./api";
import { renderMarkdown, formatTime } from "./markdown";
import { Post } from "./types";

declare const process: {
  env: { DATABASE_HOST: string; DATABASE_PATH: string; AUTH_PATH: string };
};

// ---------------------------------------------------------------------------
// Reaction config
// ---------------------------------------------------------------------------

const REACTIONS = [
  { key: ":smile:",     icon: "mdi:emoticon-happy-outline", label: "smile"     },
  { key: ":frown:",     icon: "mdi:emoticon-sad-outline",   label: "frown"     },
  { key: ":like:",      icon: "mdi:thumb-up-outline",       label: "like"      },
  { key: ":celebrate:", icon: "mdi:party-popper",           label: "celebrate" },
];

// ---------------------------------------------------------------------------
// Current reply target
// ---------------------------------------------------------------------------

let replyToPath: string | null = null;

// ---------------------------------------------------------------------------
// DOM helpers (typed getters — all elements are in index.html light DOM)
// ---------------------------------------------------------------------------

const $ = <T extends HTMLElement>(id: string) =>
  document.getElementById(id) as T;

// ---------------------------------------------------------------------------
// Main entry
// ---------------------------------------------------------------------------

async function main(): Promise<void> {
  slog.info("M3ssag1n8 starting", [
    "db",
    `${process.env.DATABASE_HOST}${process.env.DATABASE_PATH}`,
  ]);

  setupLogin();
  setupWorkspaces();
  setupChannels();
  setupPosts();
  subscribeToStateChanges();

  // Show login on startup
  showLoginModal();
}

// ---------------------------------------------------------------------------
// Login / Logout
// ---------------------------------------------------------------------------

function showLoginModal(): void {
  $("login-backdrop").classList.remove("hidden");
  const app = $("app");
  app.classList.remove("active");
  app.classList.add("app-blurred");
  app.setAttribute("aria-hidden", "true");
  const usernameInput = $<HTMLInputElement>("username-input");
  usernameInput.value = "";
  $("login-error").textContent = "";
  usernameInput.focus();
}

function hideLoginModal(): void {
  $("login-backdrop").classList.add("hidden");
  const app = $("app");
  app.classList.remove("app-blurred");
  app.classList.add("active");
  app.removeAttribute("aria-hidden");
}

function setupLogin(): void {
  const usernameInput = $<HTMLInputElement>("username-input");
  const loginBtn = $<HTMLButtonElement>("login-btn");

  const doLogin = async (): Promise<void> => {
    const username = usernameInput.value.trim();
    if (!username) {
      $("login-error").textContent = "Please enter a username.";
      return;
    }
    $("login-error").textContent = "";
    loginBtn.disabled = true;
    try {
      const token = await login(username);
      store.setState({ username, token });
      $("current-username").textContent = username;
      hideLoginModal();
      await loadWorkspaces();
    } catch (e) {
      $("login-error").textContent = e instanceof Error ? e.message : "Login failed";
    } finally {
      loginBtn.disabled = false;
    }
  };

  loginBtn.addEventListener("click", doLogin);
  usernameInput.addEventListener("keydown", (e: KeyboardEvent) => {
    if (e.key === "Enter") doLogin();
  });

  $<HTMLButtonElement>("logout-btn").addEventListener("click", async () => {
    const { token } = store.state;
    if (token) {
      try { await logout(token); } catch { /* ignore */ }
    }
    resetState();
    $("current-username").textContent = "";
    showLoginModal();
  });
}

// ---------------------------------------------------------------------------
// Workspaces
// ---------------------------------------------------------------------------

function showWsError(msg: string): void {
  const errDiv = $("ws-error");
  errDiv.classList.remove("hidden");
  $("ws-error-msg").textContent = msg;
}

function clearWsError(): void {
  $("ws-error").classList.add("hidden");
}

function setupWorkspaces(): void {
  $<HTMLButtonElement>("open-workspace-btn").addEventListener("click", () =>
    handleOpenWorkspace(),
  );
  $<HTMLButtonElement>("create-workspace-btn").addEventListener("click", () =>
    handleCreateWorkspace(),
  );
  $<HTMLButtonElement>("delete-workspace-btn").addEventListener("click", () =>
    handleDeleteWorkspace(),
  );
  $<HTMLButtonElement>("refresh-workspaces-btn").addEventListener("click", () =>
    loadWorkspaces(),
  );
  $("ws-dismiss-error").addEventListener("click", () => clearWsError());
  $<HTMLInputElement>("workspace-name-input").addEventListener("keydown", (e: KeyboardEvent) => {
    if (e.key === "Enter") handleOpenWorkspace();
  });
}

async function loadWorkspaces(): Promise<void> {
  const { token } = store.state;
  if (!token) return;
  try {
    const workspaces = await listWorkspaces(token);
    store.setState({ workspaces });
  } catch (e) {
    showWsError(e instanceof Error ? e.message : "Error loading workspaces");
  }
}

async function handleOpenWorkspace(): Promise<void> {
  const name = $<HTMLInputElement>("workspace-name-input").value.trim();
  if (!name) return;
  clearWsError();
  const { token } = store.state;
  if (!token) return;
  try {
    const channels = await apiOpenWorkspace(token, name);
    closeWorkspace();
    store.setState({ currentWorkspace: name, channels });
  } catch (e) {
    showWsError(e instanceof Error ? e.message : "Error opening workspace");
  }
}

async function handleCreateWorkspace(): Promise<void> {
  const name = $<HTMLInputElement>("workspace-name-input").value.trim();
  if (!name) return;
  clearWsError();
  const { token } = store.state;
  if (!token) return;
  try {
    await apiCreateWorkspace(token, name);
    const channels = await apiOpenWorkspace(token, name);
    closeWorkspace();
    store.setState({ currentWorkspace: name, channels });
    await loadWorkspaces();
  } catch (e) {
    showWsError(e instanceof Error ? e.message : "Error creating workspace");
  }
}

async function handleDeleteWorkspace(): Promise<void> {
  const name = $<HTMLInputElement>("workspace-name-input").value.trim();
  if (!name) return;
  clearWsError();
  const { token } = store.state;
  if (!token) return;
  try {
    await apiDeleteWorkspace(token, name);
    closeWorkspace();
    await loadWorkspaces();
  } catch (e) {
    showWsError(e instanceof Error ? e.message : "Error deleting workspace");
  }
}

function renderWorkspaceList(): void {
  const { workspaces, currentWorkspace } = store.state;
  const list = $("workspace-list");
  list.innerHTML = "";
  for (const ws of workspaces) {
    const li = document.createElement("li");
    li.className = "workspace-item" + (ws.name === currentWorkspace ? " active" : "");
    li.textContent = ws.name;
    li.title = ws.name;
    li.addEventListener("click", () => {
      $<HTMLInputElement>("workspace-name-input").value = ws.name;
      handleOpenWorkspace();
    });
    list.appendChild(li);
  }
}

// ---------------------------------------------------------------------------
// Channels
// ---------------------------------------------------------------------------

function showChError(msg: string): void {
  const errDiv = $("ch-error");
  errDiv.classList.remove("hidden");
  $("ch-error-msg").textContent = msg;
}

function clearChError(): void {
  $("ch-error").classList.add("hidden");
}

function setupChannels(): void {
  $<HTMLButtonElement>("open-channel-btn").addEventListener("click", () =>
    handleOpenChannel(),
  );
  $<HTMLButtonElement>("create-channel-btn").addEventListener("click", () =>
    handleCreateChannel(),
  );
  $<HTMLButtonElement>("delete-channel-btn").addEventListener("click", () =>
    handleDeleteChannel(),
  );
  $<HTMLButtonElement>("refresh-channels-btn").addEventListener("click", () =>
    loadChannels(),
  );
  $("ch-dismiss-error").addEventListener("click", () => clearChError());
  $<HTMLInputElement>("channel-name-input").addEventListener("keydown", (e: KeyboardEvent) => {
    if (e.key === "Enter") handleOpenChannel();
  });
}

async function loadChannels(): Promise<void> {
  const { token, currentWorkspace } = store.state;
  if (!token || !currentWorkspace) return;
  try {
    const channels = await listChannels(token, currentWorkspace);
    store.setState({ channels });
  } catch (e) {
    showChError(e instanceof Error ? e.message : "Error loading channels");
  }
}

async function handleOpenChannel(): Promise<void> {
  const name = $<HTMLInputElement>("channel-name-input").value.trim();
  if (!name) return;
  clearChError();
  const { token, currentWorkspace } = store.state;
  if (!token || !currentWorkspace) return;
  try {
    await apiOpenChannel(token, currentWorkspace, name);
    closeChannel();
    store.setState({ currentChannel: name });
    startChannelSubscription(currentWorkspace, name);
  } catch (e) {
    showChError(e instanceof Error ? e.message : "Error opening channel");
  }
}

async function handleCreateChannel(): Promise<void> {
  const name = $<HTMLInputElement>("channel-name-input").value.trim();
  if (!name) return;
  clearChError();
  const { token, currentWorkspace } = store.state;
  if (!token || !currentWorkspace) return;
  try {
    await apiCreateChannel(token, currentWorkspace, name);
    closeChannel();
    store.setState({ currentChannel: name });
    startChannelSubscription(currentWorkspace, name);
    await loadChannels();
  } catch (e) {
    showChError(e instanceof Error ? e.message : "Error creating channel");
  }
}

async function handleDeleteChannel(): Promise<void> {
  const name = $<HTMLInputElement>("channel-name-input").value.trim();
  if (!name) return;
  clearChError();
  const { token, currentWorkspace } = store.state;
  if (!token || !currentWorkspace) return;
  try {
    await apiDeleteChannel(token, currentWorkspace, name);
    closeChannel();
    await loadChannels();
  } catch (e) {
    showChError(e instanceof Error ? e.message : "Error deleting channel");
  }
}

function renderChannelList(): void {
  const { channels, currentChannel } = store.state;
  const list = $("channel-list");
  list.innerHTML = "";
  for (const ch of channels) {
    const li = document.createElement("li");
    li.className = "channel-item" + (ch.name === currentChannel ? " active" : "");
    li.textContent = ch.name;
    li.title = ch.name;
    li.addEventListener("click", () => {
      $<HTMLInputElement>("channel-name-input").value = ch.name;
      handleOpenChannel();
    });
    list.appendChild(li);
  }
}

// ---------------------------------------------------------------------------
// Posts
// ---------------------------------------------------------------------------

function setupPosts(): void {
  const submitBtn = $<HTMLButtonElement>("post-submit-btn");
  const postInput = $<HTMLTextAreaElement>("post-input");
  const closeReplyBtn = $<HTMLButtonElement>("close-reply-btn");
  const fmtBold = $<HTMLButtonElement>("fmt-bold");
  const fmtItalic = $<HTMLButtonElement>("fmt-italic");
  const fmtLink = $<HTMLButtonElement>("fmt-link");

  submitBtn.addEventListener("click", () => handleCreatePost());

  postInput.addEventListener("keydown", (e: KeyboardEvent) => {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      handleCreatePost();
    }
  });

  closeReplyBtn.addEventListener("click", () => cancelReply());

  fmtBold.addEventListener("click", () =>
    insertFormat(postInput, "**", "**", "bold text"),
  );
  fmtItalic.addEventListener("click", () =>
    insertFormat(postInput, "*", "*", "italic text"),
  );
  fmtLink.addEventListener("click", () =>
    insertFormat(postInput, "[", "](https://example.com)", "link text"),
  );

  document.querySelectorAll<HTMLButtonElement>(".reaction-insert").forEach((btn) => {
    btn.addEventListener("click", () => {
      const reaction = btn.dataset["reaction"] ?? "";
      insertAtCursor(postInput, reaction);
    });
  });
}

function insertFormat(
  textarea: HTMLTextAreaElement,
  before: string,
  after: string,
  placeholder: string,
): void {
  const start = textarea.selectionStart;
  const end = textarea.selectionEnd;
  const selected = textarea.value.substring(start, end) || placeholder;
  textarea.setRangeText(`${before}${selected}${after}`, start, end, "end");
  textarea.focus();
}

function insertAtCursor(textarea: HTMLTextAreaElement, text: string): void {
  const start = textarea.selectionStart;
  const end = textarea.selectionEnd;
  textarea.setRangeText(text, start, end, "end");
  textarea.focus();
}

async function handleCreatePost(): Promise<void> {
  const input = $<HTMLTextAreaElement>("post-input");
  const msg = input.value;
  if (!msg.trim()) return;

  const { token, currentWorkspace, currentChannel } = store.state;
  if (!token || !currentWorkspace || !currentChannel) return;

  try {
    await apiCreatePost(token, currentWorkspace, currentChannel, msg, replyToPath ?? "");
    input.value = "";
    cancelReply();
  } catch (e) {
    slog.warn("Failed to create post", ["error", e]);
  }
}

function startReply(postPath: string, postMsg: string): void {
  replyToPath = postPath;
  const ctx = $("reply-context");
  ctx.classList.remove("hidden");
  const preview = postMsg.length > 40 ? postMsg.substring(0, 40) + "…" : postMsg;
  $("reply-context-text").textContent = `Replying to: "${preview}"`;

  // Move input area to appear after the post being replied to
  const postEl = document.querySelector(`[data-path="${CSS.escape(postPath)}"]`);
  const inputArea = $("post-input-area");
  if (postEl) {
    postEl.after(inputArea);
  }
  $<HTMLTextAreaElement>("post-input").focus();
}

function cancelReply(): void {
  replyToPath = null;
  $("reply-context").classList.add("hidden");

  // Move input area back to the bottom of post section
  const postSection = $("post-section");
  const inputArea = $("post-input-area");
  postSection.appendChild(inputArea);
}

async function handleReaction(
  postPath: string,
  reactionKey: string,
  currentReactions: Record<string, string[]>,
): Promise<void> {
  const { token, username } = store.state;
  if (!token || !username) return;

  const newReactions = { ...currentReactions };
  const users = newReactions[reactionKey] ? [...newReactions[reactionKey]] : [];
  const idx = users.indexOf(username);
  if (idx >= 0) {
    users.splice(idx, 1);
  } else {
    users.push(username);
  }
  newReactions[reactionKey] = users;

  try {
    // postPath is the full DB path like /v1/m3ssag1n8/ws/channels/ch/posts/id
    await patchReactions(token, postPath, newReactions);
  } catch (e) {
    slog.warn("Failed to update reaction", ["error", e]);
  }
}

function renderPost(post: Post, byParent: Map<string, Post[]>): HTMLElement {
  const { username } = store.state;
  const reactions = (post.doc.reactions ?? {}) as Record<string, string[]>;

  const div = document.createElement("div");
  div.className = "post-item";
  div.dataset["path"] = post.path;

  const reactionHtml = REACTIONS.map((r) => {
    const users = reactions[r.key] ?? [];
    const count = users.length;
    const reacted = username ? users.includes(username) : false;
    return `<button
        class="reaction-btn${reacted ? " reacted" : ""}"
        data-reaction="${r.key}"
        aria-label="${r.label} (${count})"
        title="${r.key}"
      >
        <iconify-icon icon="${r.icon}" aria-label="${r.label}"></iconify-icon>
        <span class="reaction-count">${count}</span>
      </button>`;
  }).join("");

  div.innerHTML = `
    <div class="post-header-row">
      <span class="post-author">${escapeHtml(post.meta.createdBy || "unknown")}</span>
      <span class="post-time">${formatTime(post.meta.createdAt)}</span>
    </div>
    <div class="post-content">${renderMarkdown(post.doc.msg)}</div>
    <div class="post-actions">
      <button class="reply-btn" data-action="reply" aria-label="Reply to post">
        <iconify-icon icon="mdi:reply" aria-label="reply"></iconify-icon> Reply
      </button>
      ${reactionHtml}
    </div>
    <div class="replies"></div>
  `;

  // Reply button
  div.querySelector<HTMLButtonElement>('[data-action="reply"]')!
    .addEventListener("click", (e) => {
      e.stopPropagation();
      startReply(post.path, post.doc.msg);
    });

  // Reaction buttons
  div.querySelectorAll<HTMLButtonElement>(".reaction-btn").forEach((btn) => {
    btn.addEventListener("click", (e) => {
      e.stopPropagation();
      const key = btn.dataset["reaction"] ?? "";
      handleReaction(post.path, key, reactions);
    });
  });

  // Render nested replies
  const replies = byParent.get(post.path) ?? [];
  if (replies.length > 0) {
    const repliesDiv = div.querySelector(".replies")!;
    for (const reply of replies) {
      repliesDiv.appendChild(renderPost(reply, byParent));
    }
  }

  return div;
}

function renderPosts(): void {
  const { posts, currentChannel } = store.state;
  const postList = $("post-list");

  if (!currentChannel) {
    postList.innerHTML = '<p class="empty-state">Open a channel to see messages.</p>';
    return;
  }

  const allPosts = Array.from(posts.values());
  allPosts.sort((a, b) => {
    const ta = a.meta.createdAt;
    const tb = b.meta.createdAt;
    return ta < tb ? -1 : ta > tb ? 1 : 0;
  });

  const topLevel: Post[] = [];
  const byParent = new Map<string, Post[]>();

  for (const post of allPosts) {
    const parent = post.doc.parent ?? "";
    if (!parent) {
      topLevel.push(post);
    } else {
      if (!byParent.has(parent)) byParent.set(parent, []);
      byParent.get(parent)!.push(post);
    }
  }

  // Preserve input area position
  const postSection = $("post-section");
  const inputArea = $("post-input-area");

  postList.innerHTML = "";

  if (topLevel.length === 0) {
    postList.innerHTML = '<p class="empty-state">No messages yet.</p>';
  } else {
    for (const post of topLevel) {
      postList.appendChild(renderPost(post, byParent));
    }
  }

  // If not in reply mode, keep input at bottom
  if (!replyToPath) {
    postSection.appendChild(inputArea);
  }
}

// ---------------------------------------------------------------------------
// State subscription — react to state changes and update the UI
// ---------------------------------------------------------------------------

function subscribeToStateChanges(): void {
  store.addEventListener("state-change", () => {
    const { currentWorkspace, currentChannel } = store.state;

    // Workspace sidebar visibility
    const channelSidebar = $("channel-sidebar");
    if (currentWorkspace) {
      channelSidebar.classList.remove("hidden");
      $("current-workspace-label").textContent = currentWorkspace;
    } else {
      channelSidebar.classList.add("hidden");
      $("current-workspace-label").textContent = "";
    }

    // Post section visibility
    const postSection = $("post-section");
    if (currentChannel) {
      postSection.classList.remove("hidden");
      $("current-channel-label").textContent = currentChannel;
    } else {
      postSection.classList.add("hidden");
      $("current-channel-label").textContent = "";
    }

    renderWorkspaceList();
    renderChannelList();
    renderPosts();
  });
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function escapeHtml(text: string): string {
  return text
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#39;");
}

/* Register event handler to run after the page is fully loaded. */
document.addEventListener("DOMContentLoaded", () => {
  main();
});

