/// <reference types="cypress" />
import {
  uniqueName,
  apiLogin,
  apiCreateWorkspace,
  apiCreateChannel,
  apiLogout,
} from "./helpers";

describe("Channel Tests", () => {
  const wsName = uniqueName("ChannelTestWS");
  const extraWsName = uniqueName("ChannelTestWS2");

  before(() => {
    // Preload workspaces and channels via API
    apiLogin("channel_setup_user").then((token) => {
      apiCreateWorkspace(token, wsName);
      apiCreateChannel(token, wsName, "Existing Channel 1");
      apiCreateChannel(token, wsName, "Existing Channel 2");
      apiLogout(token);
    });

    apiLogin("channel_setup_user2").then((token) => {
      apiCreateWorkspace(token, extraWsName);
      apiCreateChannel(token, extraWsName, "Other Channel");
      apiLogout(token);
    });
  });

  beforeEach(() => {
    cy.visit("/");
    cy.login("channel_user");
    cy.openWorkspace(wsName);
  });

  afterEach(() => {
    cy.logout();
  });

  it("should display channels in open workspace", () => {
    cy.contains("Existing Channel 1").should("exist");
    cy.contains("Existing Channel 2").should("exist");
  });

  it("should open channel", () => {
    cy.openChannel("Existing Channel 1");
    cy.contains("Existing Channel 1").should("be.visible");
  });

  it("should create channel", () => {
    const newCh = uniqueName("NewCH");
    cy.createChannel(newCh);
    cy.contains(newCh).should("exist");
  });

  it("should send PUT request to create channels in workspace", () => {
    const newCh = uniqueName("PutCH");

    cy.intercept(
      "PUT",
      `${Cypress.env("DATABASE_HOST")}/**`,
    ).as("createCh");

    cy.createChannel(newCh);

    cy.wait("@createCh").then((interception) => {
      expect(interception.request.method).to.eq("PUT");
      const url = decodeURIComponent(interception.request.url);
      expect(url).to.include("channels");
      expect(url).to.include(newCh);
    });
  });

  it("should delete channel", () => {
    const delCh = uniqueName("DelCH");
    cy.createChannel(delCh);
    cy.contains(delCh).should("exist");

    cy.deleteChannel(delCh);
  });

  it("should send DELETE request to delete channel", () => {
    const delCh = uniqueName("DelReqCH");
    cy.createChannel(delCh);
    cy.contains(delCh).should("exist");

    cy.intercept(
      "DELETE",
      `${Cypress.env("DATABASE_HOST")}/**`,
    ).as("deleteCh");

    cy.deleteChannel(delCh);

    cy.wait("@deleteCh").then((interception) => {
      expect(interception.request.method).to.eq("DELETE");
    });
  });

  it("should switch channels", () => {
    cy.openChannel("Existing Channel 1");
    cy.contains("Existing Channel 1").should("be.visible");

    cy.openChannel("Existing Channel 2");
    cy.contains("Existing Channel 2").should("be.visible");
  });

  it("should close channel when workspace changes", () => {
    cy.openChannel("Existing Channel 1");
    cy.contains("Existing Channel 1").should("be.visible");

    cy.openWorkspace(extraWsName);
    cy.contains("Other Channel").should("exist");
  });

  it("should show error for duplicate channel", () => {
    cy.createChannel("Existing Channel 1");

    cy.get("body").then(($body) => {
      const hasError =
        $body.text().toLowerCase().includes("error") ||
        $body.text().toLowerCase().includes("already exists") ||
        $body.text().toLowerCase().includes("conflict") ||
        $body.find("[class*='error'], [role='alert'], .error, .toast").length >
          0;
      expect(hasError).to.be.true;
    });
  });

  it("should show error for opening non-existent channel", () => {
    const fakeCh = uniqueName("FakeCH");
    cy.openChannel(fakeCh);

    cy.get("body").then(($body) => {
      const hasError =
        $body.text().toLowerCase().includes("error") ||
        $body.text().toLowerCase().includes("not found") ||
        $body.text().toLowerCase().includes("does not exist") ||
        $body.find("[class*='error'], [role='alert'], .error, .toast").length >
          0;
      expect(hasError).to.be.true;
    });
  });

  it("should show error for deleting non-existent channel", () => {
    const fakeCh = uniqueName("FakeDelCH");
    cy.deleteChannel(fakeCh);

    cy.get("body").then(($body) => {
      const hasError =
        $body.text().toLowerCase().includes("error") ||
        $body.text().toLowerCase().includes("not found") ||
        $body.text().toLowerCase().includes("does not exist") ||
        $body.find("[class*='error'], [role='alert'], .error, .toast").length >
          0;
      expect(hasError).to.be.true;
    });
  });

  it("should not show channels from other workspaces", () => {
    cy.contains("Other Channel").should("not.exist");
  });
});

