     1→/**
     2→ * Application state management using a simple pub/sub EventTarget store.
     3→ */
     4→
     5→import { Post, Workspace, Channel } from "./types";
     6→import { SSEPostEvent, subscribeToChannel } from "./api";
     7→import { slog } from "./slog";
     8→
     9→// ---------------------------------------------------------------------------
    10→// State shape
    11→// ---------------------------------------------------------------------------
    12→
    13→export interface AppState {
    14→  /** Currently logged-in username, null if not logged in. */
    15→  username: string | null;
    16→  /** Bearer token for API calls. */
    17→  token: string | null;
    18→  /** All known workspaces. */
    19→  workspaces: Workspace[];
    20→  /** Name of the currently open workspace. */
    21→  currentWorkspace: string | null;
    22→  /** Channels in the currently open workspace. */
    23→  channels: Channel[];
    24→  /** Name of the currently open channel. */
    25→  currentChannel: string | null;
    26→  /** Posts in the currently open channel (live via SSE). */
    27→  posts: Map<string, Post>;
    28→  /** Global error message (null = no error). */
    29→  error: string | null;
    30→  /** Path of the post being replied to (null = top-level). */
    31→  replyTo: string | null;
    32→}
    33→
    34→// ---------------------------------------------------------------------------
    35→// Store
    36→// ---------------------------------------------------------------------------
    37→
    38→class AppStore extends EventTarget {
    39→  private _state: AppState = {
    40→    username: null,
    41→    token: null,
    42→    workspaces: [],
    43→    currentWorkspace: null,
    44→    channels: [],
    45→    currentChannel: null,
    46→    posts: new Map(),
    47→    error: null,
    48→    replyTo: null,
    49→  };
    50→
    51→  /** Current state snapshot. */
    52→  get state(): Readonly<AppState> {
    53→    return this._state;
    54→  }
    55→
    56→  /** Update state and notify listeners. */
    57→  setState(update: Partial<AppState>): void {
    58→    this._state = { ...this._state, ...update };
    59→    this.dispatchEvent(new CustomEvent("state-change", { detail: this._state }));
    60→  }
    61→
    62→  /** Convenience: set error. */
    63→  setError(msg: string | null): void {
    64→    this.setState({ error: msg });
    65→  }
    66→
    67→  /** Clear error. */
    68→  clearError(): void {
    69→    this.setState({ error: null });
    70→  }
    71→}
    72→
    73→export const store = new AppStore();
    74→
    75→// ---------------------------------------------------------------------------
    76→// SSE subscription management
    77→// ---------------------------------------------------------------------------
    78→
    79→let sseController: AbortController | null = null;
    80→
    81→/** Start SSE subscription for the given channel. Cancels any prior subscription. */
    82→export function startChannelSubscription(workspace: string, channel: string): void {
    83→  stopChannelSubscription();
    84→
    85→  const { token } = store.state;
    86→  if (!token) return;
    87→
    88→  sseController = subscribeToChannel(
    89→    token,
    90→    workspace,
    91→    channel,
    92→    (event: SSEPostEvent) => handleSSEEvent(event),
    93→    (err) => slog.warn("SSE error in channel subscription", ["err", err]),
    94→  );
    95→}
    96→
    97→/** Stop the current SSE subscription. */
    98→export function stopChannelSubscription(): void {
    99→  if (sseController) {
   100→    sseController.abort();
   101→    sseController = null;
   102→  }
   103→}
   104→
   105→function handleSSEEvent(event: SSEPostEvent): void {
   106→  const { posts } = store.state;
   107→  const newPosts = new Map(posts);
   108→
   109→  if (event.eventType === "delete") {
   110→    newPosts.delete(event.path);
   111→  } else if (event.doc && event.meta) {
   112→    // put or patch — upsert the post
   113→    newPosts.set(event.path, {
   114→      path: event.path,
   115→      doc: event.doc,
   116→      meta: event.meta,
   117→    });
   118→  } else if (event.eventType === "put" && event.doc) {
   119→    // put without meta — create with empty meta
   120→    newPosts.set(event.path, {
   121→      path: event.path,
   122→      doc: event.doc,
   123→      meta: { createdAt: "", createdBy: "" },
   124→    });
   125→  } else if (event.eventType === "patch" && event.doc) {
   126→    // patch — merge into existing
   127→    const existing = newPosts.get(event.path);
   128→    if (existing) {
   129→      newPosts.set(event.path, {
   130→        ...existing,
   131→        doc: { ...existing.doc, ...event.doc },
   132→      });
   133→    } else {
   134→      newPosts.set(event.path, {
   135→        path: event.path,
   136→        doc: event.doc,
   137→        meta: { createdAt: "", createdBy: "" },
   138→      });
   139→    }
   140→  }
   141→
   142→  store.setState({ posts: newPosts });
   143→}
   144→
   145→/** Reset posts and close the current channel. */
   146→export function closeChannel(): void {
   147→  stopChannelSubscription();
   148→  store.setState({ currentChannel: null, posts: new Map(), replyTo: null });
   149→}
   150→
   151→/** Reset everything related to workspace/channel when workspace closes. */
   152→export function closeWorkspace(): void {
   153→  closeChannel();
   154→  store.setState({ currentWorkspace: null, channels: [] });
   155→}
   156→
   157→/** Reset all state on logout. */
   158→export function resetState(): void {
   159→  stopChannelSubscription();
   160→  store.setState({
   161→    username: null,
   162→    token: null,
   163→    workspaces: [],
   164→    currentWorkspace: null,
   165→    channels: [],
   166→    currentChannel: null,
   167→    posts: new Map(),
   168→    error: null,
   169→    replyTo: null,
   170→  });
   171→}
