func (h *Handler) handleSubscribe(w http.ResponseWriter, r *http.Request, rawPath string, username string) {
	cleanPath := strings.Trim(rawPath, "/")
	parts := splitAndDecode(cleanPath)
	isCollection := strings.HasSuffix(rawPath, "/")

	if len(parts) == 0 {
		writeError(w, http.StatusBadRequest, "empty path")
		return
	}

	dbName := parts[0]
	dbCol, exists := h.dbm.GetDatabase(dbName)
	if !exists {
		writeError(w, http.StatusNotFound, "database not found")
		return
	}

	intervalStr := r.URL.Query().Get("interval")

	if isCollection || len(parts) == 1 {
		// Collection subscription
		var targetCol *db.Collection

		if len(parts) == 1 {
			targetCol = dbCol
		} else {
			// Navigate to collection
			currentCol := dbCol
			var currentDoc *db.Document

			navParts := parts[1:]
			for i := 0; i < len(navParts); i++ {
				if i%2 == 0 {
					d, ok := currentCol.GetDocument(navParts[i])
					if !ok {
						writeError(w, http.StatusNotFound, "document not found")
						return
					}
					currentDoc = d
				} else {
					c, ok := currentDoc.GetCollection(navParts[i])
					if !ok {
						writeError(w, http.StatusNotFound, "collection not found")
						return
					}
					currentCol = c
				}
			}
			targetCol = currentCol
		}

		var interval *Interval
		if intervalStr != "" {
			low, high, lowInc, highInc := parseInterval(intervalStr)
			interval = &Interval{Low: low, High: high, LowInclusive: lowInc, HighInclusive: highInc}
		}

		colPath := "/v1/" + cleanPath + "/"
		if strings.HasSuffix(rawPath, "/") {
			colPath = "/v1/" + cleanPath + "/"
		}
		// Normalize
		colPath = strings.ReplaceAll(colPath, "//", "/")

		sub := h.sm.SubscribeCollection(colPath, interval)
		defer h.sm.Unsubscribe(colPath, sub)

		// Send initial snapshot
		low, high, lowInc, highInc := parseInterval(intervalStr)
		docs := targetCol.ListDocuments(low, high, lowInc, highInc)
		basePath := "/v1/" + cleanPath
		for _, d := range docs {
			docPath := basePath + "/" + d.Name
			docPath = strings.ReplaceAll(docPath, "//", "/")
			resp, err := d.Doc.ToResponse(docPath)
			if err != nil {
				continue
			}
			sub.ch <- SSEEvent{
				EventType: "update",
				Data:      resp,
				ID:        fmt.Sprintf("%d", time.Now().UnixMilli()),
			}
		}

		WriteSSEStream(w, r, sub)
		return
	}

	// Document subscription
	// Navigate to document
	currentCol := dbCol
	var targetDoc *db.Document

	navParts := parts[1:]
	for i := 0; i < len(navParts); i++ {
		if i%2 == 0 {
			d, ok := currentCol.GetDocument(navParts[i])
			if !ok {
				writeError(w, http.StatusNotFound, "document not found")
				return
			}
			targetDoc = d
			if i == len(navParts)-1 {
				break
			}
		} else {
			c, ok := targetDoc.GetCollection(navParts[i])
			if !ok {
				writeError(w, http.StatusNotFound, "collection not found")
				return
			}
			currentCol = c
		}
	}

	if targetDoc == nil {
		writeError(w, http.StatusNotFound, "document not found")
		return
	}

	docPath := "/v1/" + cleanPath
	sub := h.sm.SubscribeDocument(docPath)
	defer h.sm.Unsubscribe(docPath, sub)

	// Send initial snapshot
	resp, err := targetDoc.ToResponse(docPath)
	if err == nil {
		sub.ch <- SSEEvent{
			EventType: "update",
			Data:      resp,
			ID:        fmt.Sprintf("%d", time.Now().UnixMilli()),
		}
	}

	WriteSSEStream(w, r, sub)
}

package server

import (
	"encoding/json"
	"fmt"
	"net/http"
	"sync"
	"time"
)

type SSEEvent struct {
	EventType string
	Data      interface{}
	ID        string
}

type Subscriber struct {
	ch       chan SSEEvent
	interval *Interval
	done     chan struct{}
	once     sync.Once
}

type Interval struct {
	Low           string
	High          string
	LowInclusive  bool
	HighInclusive bool
}

func (iv *Interval) Contains(name string) bool {
	if iv == nil {
		return true
	}
	if iv.Low != "" {
		if iv.LowInclusive {
			if name < iv.Low {
				return false
			}
		} else {
			if name <= iv.Low {
				return false
			}
		}
	}
	if iv.High != "" {
		if iv.HighInclusive {
			if name > iv.High {
				return false
			}
		} else {
			if name >= iv.High {
				return false
			}
		}
	}
	return true
}

type SubscriptionManager struct {
	mu             sync.RWMutex
	docSubscribers map[string][]*Subscriber
	colSubscribers map[string][]*Subscriber
}

func NewSubscriptionManager() *SubscriptionManager {
	return &SubscriptionManager{
		docSubscribers: make(map[string][]*Subscriber),
		colSubscribers: make(map[string][]*Subscriber),
	}
}

func (sm *SubscriptionManager) SubscribeDocument(path string) *Subscriber {
	sub := &Subscriber{
		ch:   make(chan SSEEvent, 100),
		done: make(chan struct{}),
	}
	sm.mu.Lock()
	sm.docSubscribers[path] = append(sm.docSubscribers[path], sub)
	sm.mu.Unlock()
	return sub
}

func (sm *SubscriptionManager) SubscribeCollection(path string, interval *Interval) *Subscriber {
	sub := &Subscriber{
		ch:       make(chan SSEEvent, 100),
		interval: interval,
		done:     make(chan struct{}),
	}
	sm.mu.Lock()
	sm.colSubscribers[path] = append(sm.colSubscribers[path], sub)
	sm.mu.Unlock()
	return sub
}

func (sm *SubscriptionManager) Unsubscribe(path string, sub *Subscriber) {
	sm.mu.Lock()
	defer sm.mu.Unlock()

	if subs, ok := sm.docSubscribers[path]; ok {
		for i, s := range subs {
			if s == sub {
				sm.docSubscribers[path] = append(subs[:i], subs[i+1:]...)
				break
			}
		}
	}

	if subs, ok := sm.colSubscribers[path]; ok {
		for i, s := range subs {
			if s == sub {
				sm.colSubscribers[path] = append(subs[:i], subs[i+1:]...)
				break
			}
		}
	}
}

func (sm *SubscriptionManager) sendEvent(subs []*Subscriber, event SSEEvent, filterDocName string) {
	for _, sub := range subs {
		if filterDocName != "" && sub.interval != nil && !sub.interval.Contains(filterDocName) {
			continue
		}
		select {
		case sub.ch <- event:
		case <-sub.done:
		default:
		}
	}
}

func (sm *SubscriptionManager) NotifyDocumentUpdate(path string, data interface{}) {
	sm.mu.RLock()
	subs := append([]*Subscriber(nil), sm.docSubscribers[path]...)
	sm.mu.RUnlock()

	event := SSEEvent{
		EventType: "update",
		Data:      data,
		ID:        fmt.Sprintf("%d", time.Now().UnixMilli()),
	}
	sm.sendEvent(subs, event, "")
}

func (sm *SubscriptionManager) NotifyDocumentDelete(path string, data interface{}) {
	sm.mu.RLock()
	subs := append([]*Subscriber(nil), sm.docSubscribers[path]...)
	sm.mu.RUnlock()

	event := SSEEvent{
		EventType: "delete",
		Data:      data,
		ID:        fmt.Sprintf("%d", time.Now().UnixMilli()),
	}
	sm.sendEvent(subs, event, "")
}

func (sm *SubscriptionManager) NotifyCollectionDocUpdate(collectionPath string, docName string, data interface{}) {
	sm.mu.RLock()
	subs := append([]*Subscriber(nil), sm.colSubscribers[collectionPath]...)
	sm.mu.RUnlock()

	event := SSEEvent{
		EventType: "update",
		Data:      data,
		ID:        fmt.Sprintf("%d", time.Now().UnixMilli()),
	}
	sm.sendEvent(subs, event, docName)
}

func (sm *SubscriptionManager) NotifyCollectionDocDelete(collectionPath string, docName string, data interface{}) {
	sm.mu.RLock()
	subs := append([]*Subscriber(nil), sm.colSubscribers[collectionPath]...)
	sm.mu.RUnlock()

	event := SSEEvent{
		EventType: "delete",
		Data:      data,
		ID:        fmt.Sprintf("%d", time.Now().UnixMilli()),
	}
	sm.sendEvent(subs, event, docName)
}

func (sm *SubscriptionManager) NotifyCollectionDelete(collectionPath string) {
	sm.mu.RLock()
	subs := append([]*Subscriber(nil), sm.colSubscribers[collectionPath]...)
	sm.mu.RUnlock()

	event := SSEEvent{
		EventType: "delete",
		Data:      map[string]interface{}{"path": collectionPath},
		ID:        fmt.Sprintf("%d", time.Now().UnixMilli()),
	}
	// All subscribers get collection delete regardless of interval
	for _, sub := range subs {
		select {
		case sub.ch <- event:
		case <-sub.done:
		default:
		}
	}
}

func WriteSSEStream(w http.ResponseWriter, r *http.Request, sub *Subscriber) {
	flusher, ok := w.(http.Flusher)
	if !ok {
		http.Error(w, "streaming not supported", http.StatusInternalServerError)
		return
	}

	w.Header().Set("Content-Type", "text/event-stream")
	w.Header().Set("Cache-Control", "no-cache")
	w.Header().Set("Connection", "keep-alive")
	w.Header().Set("Access-Control-Allow-Origin", "*")
	w.WriteHeader(http.StatusOK)
	flusher.Flush()

	keepAlive := time.NewTicker(15 * time.Second)
	defer keepAlive.Stop()

	ctx := r.Context()

	for {
		select {
		case event, ok := <-sub.ch:
			if !ok {
				return
			}
			dataBytes, err := json.Marshal(event.Data)
			if err != nil {
				continue
			}
			fmt.Fprintf(w, "event: %s\n", event.EventType)
			fmt.Fprintf(w, "data: %s\n", string(dataBytes))
			fmt.Fprintf(w, "id: %s\n\n", event.ID)
			flusher.Flush()

		case <-keepAlive.C:
			fmt.Fprintf(w, ": keepalive\n\n")
			flusher.Flush()

		case <-ctx.Done():
			sub.once.Do(func() { close(sub.done) })
			return
		}
	}
}

func (h *Handler) handlePatch(w http.ResponseWriter, r *http.Request, rawPath string, username string) {
