	if len(parts) == 2 {
		d, ok := parentCol.GetDocument(docName)
		if !ok {
			writeError(w, http.StatusNotFound, "document not found")
			return
		}
		targetDoc = d
	} else if len(parts) > 2 {
		navParts := parts[1 : len(parts)-1]
		var currentDoc *db.Document

		for i := 0; i < len(navParts); i++ {
			if i%2 == 0 {
				d, ok := parentCol.GetDocument(navParts[i])
				if !ok {
					writeError(w, http.StatusNotFound, "parent not found")
					return
				}
				currentDoc = d
			} else {
				c, ok := currentDoc.GetCollection(navParts[i])
				if !ok {
					writeError(w, http.StatusNotFound, "collection not found")
					return
				}
				parentCol = c
			}
		}

		d, ok := parentCol.GetDocument(docName)
		if !ok {
			writeError(w, http.StatusNotFound, "document not found")
			return
		}
		targetDoc = d
	} else {
		writeError(w, http.StatusBadRequest, "invalid patch path")
		return
	}

	body, err := io.ReadAll(r.Body)
	if err != nil {
		writeError(w, http.StatusBadRequest, "failed to read body")
		return
	}

	var patches []db.PatchOp
	if err := json.Unmarshal(body, &patches); err != nil {
		writeError(w, http.StatusBadRequest, "invalid JSON")
		return
